As a temporary fix I made this workaround:

```py
import asyncio

import aiohttp
import async_timeout
import telepot.aio
from telepot.aio.api import (
    _proxy, _parse, _compose_timeout, _compose_data, _methodurl
)
from telepot.exception import TelegramError


class Bot(telepot.aio.Bot):

    async def request(self, req, **user_kw):
        fn, args, kwargs, timeout, cleanup = self._transform(req, **user_kw)

        if _proxy:
            kwargs['proxy'] = _proxy[0]
            if len(_proxy) > 1:
                kwargs['proxy_auth'] = aiohttp.BasicAuth(*_proxy[1])

        try:
            if timeout is None:
                async with fn(*args, **kwargs) as r:
                    return await _parse(r)
            else:
                try:
                    with async_timeout.timeout(timeout):
                        async with fn(*args, **kwargs) as r:
                            return await _parse(r)

                except asyncio.TimeoutError:
                    raise TelegramError('Response timeout', 504, {})

        except aiohttp.ClientConnectionError:
            raise TelegramError('Connection Error', 400, {})

        finally:
            if cleanup:
                cleanup()  # e.g. closing one-time session

    async def _api_request(self, method, params=None, files=None, **kwargs):
        return await self.request((self._token, method, params, files), **kwargs)

    def _transform(self, req, **user_kw):
        timeout = _compose_timeout(req, **user_kw)
        data = _compose_data(req, **user_kw)
        url = _methodurl(req, **user_kw)
        session = aiohttp.ClientSession(
            connector=aiohttp.TCPConnector(limit=1, force_close=True),
            loop=self.loop)

        cleanup = session.close

        kwargs = {'data': data}
        kwargs.update(user_kw)

        return session.post, (url,), kwargs, timeout, cleanup
```
Now Bot doesn't lose loop. I'm not sure that it should be fixed in the code of the telepot, but if you want to make it working inside other asyncio frameworks I may have a reason to make loop linked to the calls made by the aiohttp.

I believe I've now got matching quotes working quite well. Went over all the unicode characters marked with `Quotation Mark=Yes` (30 in total) and paired them together. Had to make the values in the dictionary into a list, since some had two kinds of closing quotes. Final result in full is this:
```
def quoted_word(view):
    quotes = {
        '"': ['"'],
        "'": ["'"],
        "«": ["»"],
        "‘": ["’"],
        "‚": ["‛"],
        "“": ["”"],
        "„": ["‟"],
        "‹": ["›"],
        "⹂": ["⹂"],
        "「": ["」"],
        "『": ["』"],
        "〝": ["〞", "〟"],
        "﹁": ["﹂"],
        "﹃": ["﹄"],
        "＂": ["＂"],
        "＇": ["＇"],
        "｢": ["｣"]
    }
    current = view.current

    if current is None:
        return None

    is_quoted = False
    if current in quotes.keys():
        opening_quote = current
        is_quoted = True
    result = [] if is_quoted else [current]

    while not view.eof:
        current = view.get()
        if not current:
            if is_quoted:
                # unexpected EOF
                raise BadArgument('Expected closing "')
            return ''.join(result)

        # currently we accept strings in the format of "hello world"
        # to embed a quote inside the string you must escape it: "a \"world\""
        if current == '\\':
            next_char = view.get()
            if not next_char:
                # string ends with \ and no character after it
                if is_quoted:
                    # if we're quoted then we're expecting a closing quote
                    raise BadArgument('Expected closing "')
                # if we aren't then we just let it through
                return ''.join(result)

            if next_char in quotes[opening_quote]:
                # escaped quote
                result.append('"')
            else:
                # different escape character, ignore it
                view.undo()
                result.append(current)
            continue

        # closing quote
        if current in quotes[opening_quote]:
            next_char = view.get()
            valid_eof = not next_char or next_char.isspace()
            if is_quoted:
                if not valid_eof:
                    raise BadArgument('Expected space after closing quotation')

                # we're quoted so it's okay
                return ''.join(result)
            else:
                # we aren't quoted
                raise BadArgument('Unexpected quote mark in non-quoted string')

        if current.isspace() and not is_quoted:
            # end of word found
            return ''.join(result)

        result.append(current)
```

